:host([hidden]){display:none}
*{box-sizing:border-box}
.frame{position:relative;display:grid;min-height:360px;overflow:hidden;place-items:center;border:1px solid var(--_line);border-radius:18px;background:var(--_bg);box-shadow:0 12px 32px rgba(15,23,42,.07)}
