if(data.eyebrow)content.appendChild(make('div','eyebrow',String(data.eyebrow)));content.appendChild(make('h2','',headline));
if(data.subtext)content.appendChild(make('p','subtext',String(data.subtext)));
if(data.cta){content.appendChild(make('span','cta',String(data.cta)));if(data.ctaNote)content.appendChild(make('div','note',String(data.ctaNote)));}
frame.appendChild(content);root.appendChild(frame);
parent.appendChild(host);

